class Solution:
    def sumOfPower(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        total = 0
        for mask in range(1, 1 << n):
            mx = 0
            mn = None
            for i in range(n):
                if mask & (1 << i):
                    v = nums[i]
                    if v > mx:
                        mx = v
                    if mn is None or v < mn:
                        mn = v
            total += mx * mx * mn
        return total % MOD

