class Solution:
    def sumOfPower(self, nums):
        MOD = 10 ** 9 + 7
        arr = sorted(nums)
        g = 0
        total = 0
        for x in arr:
            total = (total + (x * x % MOD) * ((x + g) % MOD)) % MOD
            g = (2 * g + x) % MOD
        return total

