var sumOfPower = function(nums) {
    const MOD = 1000000007n;
    const arr = nums.slice().sort((a, b) => a - b);
    let g = 0n;
    let total = 0n;
    for (const xNum of arr) {
        const x = BigInt(xNum);
        total = (total + ((x * x) % MOD) * ((x + g) % MOD)) % MOD;
        g = (2n * g + x) % MOD;
    }
    return Number(total);
};
